+import React, { useState } from 'react';
+
+function AgentAvatar({ agent }) {
+  const [hover, setHover] = useState(false);
+
+  return (
+    <div
+      className="agent-avatar"
+      onMouseEnter={() => setHover(true)}
+      onMouseLeave={() => setHover(false)}
+      style={{ position: 'relative', display: 'inline-block' }}
+    >
+      <img src={agent.avatarUrl} alt={agent.name} />
+      {hover && (
+        <div className="tooltip-panel">
+          <div className="tooltip-header">🛡️ {agent.name}</div>
+          <div><strong>Tier:</strong> {agent.tier}</div>
+          <div><strong>Status:</strong> {agent.status}</div>
+          <div><strong>Task:</strong> {agent.currentTask}</div>
+          <div><strong>Tokens:</strong> {agent.tokenBudget}</div>
+        </div>
+      )}
+    </div>
+  );
+}
+
+export default AgentAvatar;
